{
"type": "visualization",
"style": "line",
"title": "Trend of Fertility Rate in Indonesia Over Time",
"subtitle": "Data from World Bank Indicators API",
"data": {
"url": "https://api.worldbank.org/v2/country/IDN/indicator/SP.DYN.TFRT.IN?format=json&per_page=10000",
"transform": [
{
"type": "filter",
"test": {
"field": "year",
"gte": 1960,
"lte": 2024
}
},
{
"type": "groupby",
"groups": [
{"field": "year"},
{"field": "fertility_rate"}
]
},
{
"type": "timeseries",
"time_field": "year",
"start": 1960,
"end": 2024,
"granularity": "year"
}
]
},
"marks": [
{
"type": "line",
"encode": {
"enter": {
"x": {"field": "year", "timeUnit": "year"},
"y": {"field": "fertility_rate", "aggregate": "mean"},
"stroke": {"value": "#4C72B0"}
}
},
"transform": [
{"type": "filter", "test": "datum.year >= 1960 && datum.year <= 2024"}
]
}
],
"scales": [
{
"name": "xscale",
"type": "time",
"domain": {"data": "data", "field": "year"},
"range": "width"
},
{
"name": "yscale",
"type": "linear",
"domain": {"data": "data", "field": "fertility_rate", "aggregate": "mean"},
"range": "height",
"nice": true,
"zero": false
}
],
"axes": [
{
"scale": "xscale",
"orient": "bottom",
"title": "Year"
},
{
"scale": "yscale",
"orient": "left",
"title": "Fertility Rate (births per woman)"
}
]
}

{
