{
"type": "visualization",
"version": "1.0.0",
"spec": {
    "$schema": "https://vega.github.io/schema/vega/v5.json",
    "width": 800,
    "height": 400,
    "padding": 5,

    "data": [
        {
            "name": "source",
            "url": "https://api.worldbank.org/v2/country/IDN/indicator/SP.DYN.TFRT.IN?format=json&per_page=1000&date=latest-10to2024",
            "format": {
                "type": "json",
                "parse": {
                    "year": "data.date",
                    "fertility_rate": "data.value"
                }
            },
            "transform": [
                {
                    "type": "filter",
                    "test": "datum.country === 'Indonesia'"
                },
                {
                    "type": "window",
                    "sort": [{"field": "year"}],
                    "ops": [
                        {"field": "year", "op": "sequential", "as": "rank_year"}
                    ],
                    "frame": [0, null]
                },
                {
                    "type": "filter",
                    "test": "datum.rank_year >= 1 and datum.rank_year <= 10"
                }
            ]
        }
    ],

    "marks": [
        {
            "type": "line",
            "from": {"data": "source"},
            "encode": {
                "enter": {
                    "x": {"field": "year", "scale": "x", "type": "temporal"},
                    "y": {"field": "fertility_rate", "scale": "y", "type": "quantitative"},
                    "stroke": {"value": "steelblue"}
                },
                "update": {
                    "interpolate": {"value": "monotone"}
                }
            }
        }
    ],

    "scales": [
        {
            "name": "x",
            "type": "time",
            "domain": {"data": "source", "field": "year"},
            "range": "width"
        },
        {
            "name": "y",
            "type": "linear",
            "domain": {"data": "source", "field": "fertility_rate"},
            "range": "height",
            "zero": true,
            "nice": true
        }
    ],

    "axes": [
        {
            "orient": "bottom",
            "scale": "x",
            "title": "Year"
        },
        {
            "orient": "left",
            "scale": "y",
            "title": "Fertility Rate (births per woman)"
        }
    ]
}
}

